SELECT g.*, prd.prod_nm AS prod_nm, ste.site_nm AS site_nm, cd_gt.code_label AS gift_type_cd_nm, cd_gs.code_label AS gift_status_cd_nm, cd_mg.code_label AS mem_grade_cd_nm FROM pm_gift g LEFT JOIN pd_prod prd ON prd.prod_id = g.prod_id LEFT JOIN sy_site ste ON ste.site_id = g.site_id LEFT JOIN sy_code cd_gt ON cd_gt.code_grp = 'GIFT_TYPE' AND cd_gt.code_value = g.gift_type_cd LEFT JOIN sy_code cd_gs ON cd_gs.code_grp = 'GIFT_STATUS' AND cd_gs.code_value = g.gift_status_cd LEFT JOIN sy_code cd_mg ON cd_mg.code_grp = 'MEMBER_GRADE' AND cd_mg.code_value = g.mem_grade_cd
ORDER BY g.gift_id ASC ORDER BY g.gift_id DESC ORDER BY g.gift_nm ASC ORDER BY g.gift_nm DESC ORDER BY g.reg_date ASC ORDER BY g.reg_date DESC ORDER BY g.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT g.*, prd.prod_nm AS prod_nm, ste.site_nm AS site_nm, cd_gt.code_label AS gift_type_cd_nm, cd_gs.code_label AS gift_status_cd_nm, cd_mg.code_label AS mem_grade_cd_nm FROM pm_gift g LEFT JOIN pd_prod prd ON prd.prod_id = g.prod_id LEFT JOIN sy_site ste ON ste.site_id = g.site_id LEFT JOIN sy_code cd_gt ON cd_gt.code_grp = 'GIFT_TYPE' AND cd_gt.code_value = g.gift_type_cd LEFT JOIN sy_code cd_gs ON cd_gs.code_grp = 'GIFT_STATUS' AND cd_gs.code_value = g.gift_status_cd LEFT JOIN sy_code cd_mg ON cd_mg.code_grp = 'MEMBER_GRADE' AND cd_mg.code_value = g.mem_grade_cd
ORDER BY g.gift_id ASC ORDER BY g.gift_id DESC ORDER BY g.gift_nm ASC ORDER BY g.gift_nm DESC ORDER BY g.reg_date ASC ORDER BY g.reg_date DESC ORDER BY g.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

