site_id = #{siteId}, gift_nm = #{giftNm}, gift_type_cd = #{giftTypeCd}, prod_id = #{prodId}, gift_stock = #{giftStock}, gift_desc = #{giftDesc}, start_date = #{startDate}, end_date = #{endDate}, gift_status_cd = #{giftStatusCd}, gift_status_cd_before = #{giftStatusCdBefore}, mem_grade_cd = #{memGradeCd}, min_order_amt = #{minOrderAmt}, min_order_qty = #{minOrderQty}, self_cdiv_rate = #{selfCdivRate}, seller_cdiv_rate = #{sellerCdivRate}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE gift_id = #{giftId}
